joi_block.script:
if (all(#PresenceSensor #Floor1).presenceSensor_presence ==| false) {
all(#Light #Switch #Floor1).switch_off()
}
else {
all(#Light #Switch #Floor1).switch_off()
}
delay(1 HOUR)
if (all(#PresenceSensor #Floor2).presenceSensor_presence ==| false) {
all(#Light #Switch #Floor2).switch_off()
}
else {
all(#Light #Switch #Floor2).switch_off()
}

